#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-20

# Security Tests: JSON-island HTML breakout in playgrounds (#3019)
#
# Playgrounds embed their state in an HTML JSON island:
#   <script type="application/json" id="lpp-state">{ ... }</script>
#
# The `type="application/json"` attribute is IRRELEVANT to the HTML tokenizer.
# Any `</script` sequence inside that block terminates the element at PARSE time,
# before JSON.parse and before any renderer-side sanitizer (esc / stCls / riskColor
# / safeUrl) has a chance to run. The remainder of the state is then parsed as live
# markup. JSON.stringify does NOT escape `<`, so a writer emitting a plan title of
#   "My plan</script><img src=x onerror=...>"
# ships a working XSS that no JavaScript-level guard can reach and that CodeQL's
# js/xss-through-dom does not model (it is an HTML-parser issue, not a JS dataflow).
#
# INVARIANT: inside a JSON island, `<` MUST be written as the < escape.
# That is valid JSON, round-trips to `<` through JSON.parse, and is inert to the
# HTML tokenizer.
#
# Priority: HIGH
# Reference: OWASP A03 (Injection) / DOM XSS via markup breakout

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED=$'\033[0;31m'; GREEN=$'\033[0;32m'; YELLOW=$'\033[1;33m'; NC=$'\033[0m'
PASS=0; FAIL=0
log_pass() { echo "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }
section() { echo; echo "${YELLOW}$1${NC}"; }

echo "=========================================="
echo "  JSON-Island Breakout Tests (#3019)"
echo "=========================================="

# ---------------------------------------------------------------------------
section "1. No shipped playground contains a raw breakout sequence"
# ---------------------------------------------------------------------------
# Scan every HTML file that declares a JSON island. Within the island body only,
# a literal `</script` (other than the island's own closing tag) is a breakout.
VIOLATIONS=$(python3 - "$PROJECT_ROOT" <<'PY'
import os, re, sys
root = sys.argv[1]
bad = []
for base, dirs, files in os.walk(root):
    dirs[:] = [d for d in dirs if d not in {".git", "node_modules", ".worktrees"}]
    for name in files:
        if not name.endswith(".html"):
            continue
        p = os.path.join(base, name)
        try:
            text = open(p, encoding="utf-8", errors="replace").read()
        except OSError:
            continue
        for m in re.finditer(
            r'<script[^>]*type=["\']application/json["\'][^>]*>(.*?)</script\s*>',
            text, re.S | re.I,
        ):
            body = m.group(1)
            if re.search(r'</script', body, re.I):
                bad.append(os.path.relpath(p, root))
for b in sorted(set(bad)):
    print(b)
PY
)
if [ -z "$VIOLATIONS" ]; then
  log_pass "no JSON island contains a raw </script sequence"
else
  log_fail "JSON island breakout present in:"
  echo "$VIOLATIONS" | sed 's/^/      /'
fi

# ---------------------------------------------------------------------------
section "2. The breakout is real (proves the test guards something)"
# ---------------------------------------------------------------------------
# A guard nobody can trigger is theatre. Build the hostile document and confirm a
# real HTML tokenizer lifts an executable element out of the island.
if python3 - <<'PY'
import json, sys
from html.parser import HTMLParser

payload = json.dumps({"title": 'plan</script><img src=x onerror="alert(1)">'})
page = f'<script type="application/json" id="s">{payload}</script>'

class T(HTMLParser):
    escaped = False
    def handle_starttag(self, tag, attrs):
        if tag == "img" and any(k == "onerror" for k, _ in attrs):
            T.escaped = True

T().feed(page)
sys.exit(0 if T.escaped else 1)
PY
then
  log_pass "unescaped island demonstrably yields a live <img onerror> element"
else
  log_fail "could not reproduce the breakout — test may no longer guard anything"
fi

# ---------------------------------------------------------------------------
section "3. The \\u003c escape neutralises it and round-trips"
# ---------------------------------------------------------------------------
if python3 - <<'PY'
import json, sys
from html.parser import HTMLParser

original = 'plan</script><img src=x onerror="alert(1)">'
escaped = json.dumps({"title": original}).replace("<", "\\u003c")

class T(HTMLParser):
    escaped_out = False
    def handle_starttag(self, tag, attrs):
        if tag == "img":
            T.escaped_out = True

T().feed(f'<script type="application/json" id="s">{escaped}</script>')
round_trips = json.loads(escaped)["title"] == original
sys.exit(0 if (not T.escaped_out and round_trips) else 1)
PY
then
  log_pass "\\u003c blocks the breakout AND JSON.parse still yields the original '<'"
else
  log_fail "\\u003c escape did not behave as required"
fi

# ---------------------------------------------------------------------------
section "4. The invariant is documented where writers will see it"
# ---------------------------------------------------------------------------
TEMPLATE="$PROJECT_ROOT/src/skills/shared/assets/playground-exemplars/living-plan.template.html"
STANDARD="$PROJECT_ROOT/src/skills/shared/rules/playground-visual-standard.md"
if [ -f "$TEMPLATE" ] && grep -q 'u003c' "$TEMPLATE"; then
  log_pass "exemplar template states the \\u003c invariant"
else
  log_fail "exemplar template does not document the \\u003c invariant"
fi
if [ -f "$STANDARD" ] && grep -q 'u003c' "$STANDARD"; then
  log_pass "playground visual standard states the \\u003c invariant"
else
  log_fail "playground visual standard does not document the \\u003c invariant"
fi

echo
echo "=========================================="
echo "  Passed: ${GREEN}${PASS}${NC}  Failed: ${RED}${FAIL}${NC}"
echo "=========================================="
[ "$FAIL" -eq 0 ]
